const params = $('Get Tax Params').first().json;
const brackets = $('Get Tax Brackets').all().map(i => i.json);
const webhookData = $('Webhook Trigger').first().json;
const lastMsg = webhookData.body.messages.filter(m => m.role === 'user').pop().content;

// 1. Detección de Monto Bruto
const amountMatch = lastMsg.match(/(\d+[\d\.,]*)/);
if (!amountMatch) return { json: { ...webhookData, tax_calc: null } };

let bruteMsg = parseFloat(amountMatch[0].replace(/\./g, '').replace(',', '.'));
if (bruteMsg < 100) bruteMsg *= 1000000;
else if (bruteMsg < 10000) bruteMsg *= 1000;

// 2. Detección de Bono / Extra / Aguinaldo
let bonusMsg = 0;
const bonusMatch = lastMsg.match(/(?:bono|extra|aguinaldo).*?(\d+[\d\.,]*)/i);
if (bonusMatch) {
    bonusMsg = parseFloat(bonusMatch[1].replace(/\./g, '').replace(',', '.'));
    if (bonusMsg < 1000) bonusMsg *= 1000; // Caso para "bono de 500k"
}

// 3. Cargas Familiares (Hijos y Cónyuge)
let hijos = 0;
const hMatch = lastMsg.match(/(\d+)\s*hijo/i);
if (hMatch) {
    hijos = parseInt(hMatch[1]);
} else if (lastMsg.includes('un hijo')) {
    hijos = 1;
}

const conyuge = lastMsg.toLowerCase().includes('conyuge') || lastMsg.toLowerCase().includes('pareja');

// 4. Parámetros de Deducciones
const gni = parseFloat(params.gni);
const especial = parseFloat(params.deduccion_especial);
const aportesPct = parseFloat(params.aportes_pct);

// 5. Cálculo de Base Imponible
const netoAnual = (bruteMsg * 13 + bonusMsg) * (1 - aportesPct);
let deducciones = gni + especial;
deducciones += hijos * parseFloat(params.hijo);
if (conyuge) deducciones += parseFloat(params.conyuge);

const base = Math.max(0, netoAnual - deducciones);

// 6. Cálculo del Impuesto según Escalas (Brackets)
let impuestoAnual = 0;
if (base > 0) {
    let bracket = brackets[0];
    for (const b of brackets) {
        if (base > parseFloat(b.limit_amount)) {
            bracket = b;
        } else {
            break;
        }
    }
    const exceso = base - parseFloat(bracket.limit_amount);
    impuestoAnual = parseFloat(bracket.fixed_amount) + (exceso * parseFloat(bracket.pct));
}

// 7. Resultado
return [{
    json: {
        ...webhookData,
        tax_calc: {
            bruto: bruteMsg,
            bonus: bonusMsg,
            netoMensual: (netoAnual - impuestoAnual) / 13,
            impuestoMensual: impuestoAnual / 12,
            base,
            hijos,
            conyuge
        }
    }
}];

